import re
from typing import AnyStr, cast, List, overload, Sequence, Tuple, TYPE_CHECKING, Union

from ._abnf import field_name, field_value
from ._util import bytesify, LocalProtocolError, validate

if TYPE_CHECKING:
    from ._events import Request

try:
    from typing import Literal
except ImportError:
    from typing_extensions import Literal  # type: ignore

CONTENT_LENGTH_MAX_DIGITS = 20  # allow up to 1 billion TB - 1


# Facts
# -----
#
# Headers are:
#   keys: case-insensitive ascii
#   values: mixture of ascii and raw bytes
#
# "Historically, HTTP has allowed field content with text in the ISO-8859-1
# charset [ISO-8859-1], supporting other charsets only through use of
# [RFC2047] encoding.  In practice, most HTTP header field values use only a
# subset of the US-ASCII charset [USASCII]. Newly defined header fields SHOULD
# limit their field values to US-ASCII octets.  A recipient SHOULD treat other
# octets in field content (obs-text) as opaque data."
# And it deprecates all non-ascii values
#
# Leading/trailing whitespace in header names is forbidden
#
# Values get leading/trailing whitespace stripped
#
# Content-Disposition actually needs to contain unicode semantically; to
# accomplish this it has a terrifically weird way of encoding the filename
# itself as ascii (and even this still has lots of cross-browser
# incompatibilities)
#
# Order is important:
# "a proxy MUST NOT change the order of these field values when forwarding a
# message"
# (and there are several headers where the order indicates a preference)
#
# Multiple occurences of the same header:
# "A sender MUST NOT generate multiple header fields with the same field name
# in a message unless either the entire field value for that header field is
# defined as a comma-separated list [or the header is Set-Cookie which gets a
# special exception]" - RFC 7230. (cookies are in RFC 6265)
#
# So every header aside from Set-Cookie can be merged by b", ".join if it
# occurs repeatedly. But, of course, they can't necessarily be split by
# .split(b","), because quoting.
#
# Given all this mess (case insensitive, duplicates allowed, order is
# important, ...), there doesn't appear to be any standard way to handle
# headers in Python -- they're almost like dicts, but... actually just
# aren't. For now we punt and just use a super simple representation: headers
# are a list of pairs
#
#   [(name1, value1), (name2, value2), ...]
#
# where all entries are bytestrings, names are lowercase and have no
# leading/trailing whitespace, and values are bytestrings with no
# leading/trailing whitespace. Searching and updating are done via naive O(n)
# methods.
#
# Maybe a dict-of-lists would be better?

_content_length_re = re.compile(rb"[0-9]+")
_field_name_re = re.compile(field_name.encode("ascii"))
_field_value_re = re.compile(field_value.encode("ascii"))


class Headers(Sequence[Tuple[bytes, bytes]]):
    """
    A list-like interface that allows iterating over headers as byte-pairs
    of (lowercased-name, value).

    Internally we actually store the representation as three-tuples,
    including both the raw original casing, in order to preserve casing
    over-the-wire, and the lowercased name, for case-insensitive comparisions.

    r = Request(
        method="GET",
        target="/",
        headers=[("Host", "example.org"), ("Connection", "keep-alive")],
        http_version="1.1",
    )
    assert r.headers == [
        (b"host", b"example.org"),
        (b"connection", b"keep-alive")
    ]
    assert r.headers.raw_items() == [
        (b"Host", b"example.org"),
        (b"Connection", b"keep-alive")
    ]
    """

    __slots__ = "_full_items"

    def __init__(self, full_items: List[Tuple[bytes, bytes, bytes]]) -> None:
        """Initialize Headers.

        full_items should be a list of 3-tuples:
            (raw_name_bytes, lowercased_name_bytes, value_bytes)

        The public interface exposes only (lowercased_name, value) pairs.
        """
        self._full_items = full_items

    def __bool__(self) -> bool:
        """Return True if there are any headers present."""
        return bool(self._full_items)

    def __eq__(self, other: object) -> bool:
        """Equality compares the visible (lowercased, value) pairs sequence."""
        return list(self) == list(other)  # type: ignore

    def __len__(self) -> int:
        """Return the number of header entries."""
        return len(self._full_items)

    def __repr__(self) -> str:
        """Return a representation useful for debugging."""
        return f"Headers({list(self)})"

    @overload
    def __getitem__(self, i: int) -> Tuple[bytes, bytes]:
        ...

    @overload
    def __getitem__(self, s: slice) -> List[Tuple[bytes, bytes]]:
        ...

    def __getitem__(self, i):
        """Retrieve a header by index or return a list of headers for a slice.

        When indexed by integer, returns (lowercased_name, value).
        When given a slice, returns a list of such tuples.
        """
        if isinstance(i, slice):
            return [(lower, value) for (_raw, lower, value) in self._full_items[i]]
        raw, lower, value = self._full_items[i]
        return cast(Tuple[bytes, bytes], (lower, value))

    def raw_items(self) -> List[Tuple[bytes, bytes]]:
        """Return the raw (original-case-name, value) header pairs in order."""
        return [(raw, value) for (raw, _lower, value) in self._full_items]


def normalize_and_validate(name: AnyStr, value: AnyStr) -> Tuple[bytes, bytes, bytes]:
    """Normalize header name/value and validate according to HTTP/1.1 rules.

    Returns a 3-tuple:
        (raw_name_bytes, lowercased_name_bytes, value_bytes)

    - Names are converted to bytes (if necessary), must not have leading or
      trailing whitespace, and must match the ABNF for field-name.
    - The lowercased name is produced for case-insensitive comparisons.
    - Values are converted to bytes (if necessary) and stripped of leading
      and trailing SP or HTAB characters. The stripped value must match the
      ABNF for field-value.
    - Raises LocalProtocolError on invalid inputs.
    """
    raw_name = bytesify(name)
    # Header names must not have leading/trailing whitespace
    if raw_name.strip() != raw_name:
        raise LocalProtocolError(f"Invalid header name (leading/trailing whitespace): {raw_name!r}")
    # Header name must match the ABNF for field-name
    if not _field_name_re.fullmatch(raw_name):
        raise LocalProtocolError(f"Invalid header name: {raw_name!r}")
    lower_name = raw_name.lower()

    raw_value = bytesify(value)
    # Strip only SP and HTAB from start/end per RFC7230
    stripped_value = raw_value.strip(b" \t")
    # Validate against field-value ABNF
    if not _field_value_re.fullmatch(stripped_value):
        raise LocalProtocolError(f"Invalid header value for {raw_name!r}: {stripped_value!r}")

    return raw_name, lower_name, stripped_value


def get_comma_header(headers: Sequence[Tuple[bytes, bytes]], name: AnyStr) -> Union[bytes, None]:
    """Return the comma-joined value of all headers matching `name`.

    The returned value is a bytes object consisting of header values joined by
    b", ". If no header with the given name exists, returns None.
    """
    wanted = bytesify(name).lower()
    found: List[bytes] = []
    for key, value in headers:
        if key.lower() == wanted:
            found.append(value)
    if not found:
        return None
    return b", ".join(found)


def set_comma_header(headers: Sequence[Tuple[bytes, bytes]], name: AnyStr, value: AnyStr) -> List[Tuple[bytes, bytes]]:
    """Return a new headers sequence where all headers matching `name` are
    replaced by a single header with the provided `value`.

    The returned list contains (lowercased_name, value) pairs.
    """
    name_bytes = bytesify(name)
    lower_name = name_bytes.lower()
    value_bytes = bytesify(value)
    new_headers: List[Tuple[bytes, bytes]] = []
    for key, val in headers:
        if key.lower() != lower_name:
            new_headers.append((key, val))
    new_headers.append((lower_name, value_bytes))
    return new_headers


def has_expect_100_continue(headers: Sequence[Tuple[bytes, bytes]]) -> bool:
    """Return True if the headers indicate an 'Expect: 100-continue' request.

    This inspects any Expect header(s), splits comma-separated tokens, and
    checks (case-insensitively) for '100-continue'.
    """
    found = get_comma_header(headers, b"expect")
    if found is None:
        return False
    # Split on commas and check each token for the exact match
    tokens = [token.strip() for token in found.split(b",")]
    for token in tokens:
        if token.lower() == b"100-continue":
            return True
    return False